(function () {
  window.DENO_DOC_SEARCH_INDEX = {"kind":"search","nodes":[{"id":"namespace_cidr4","kind":[{"char":"T","kind":"TypeAlias","title":"Type Alias"}],"name":"Cidr4","file":"cidrv4.ts","doc":"Represents an IPv4 CIDR block.Contains only the parsed values from the CIDR notation.","url":"./cidrv4.ts/~/Cidr4.html","deprecated":false},{"id":"namespace_cidr4","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"Cidr4.address","file":"cidrv4.ts","doc":"The IPv4 address from the CIDR notation","url":"./cidrv4.ts/~/Cidr4.address.html","deprecated":false},{"id":"namespace_cidr4","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"Cidr4.prefixLength","file":"cidrv4.ts","doc":"The prefix length (0-32)","url":"./cidrv4.ts/~/Cidr4.prefixLength.html","deprecated":false},{"id":"namespace_cidr4addresses","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidr4Addresses","file":"cidrv4.ts","doc":"Generates a range of IP addresses from a CIDR block.Yields IP addresses starting at the specified offset from the network address. The offset is relative to the network address (offset 0 = network address). The step parameter controls the increment (positive or negative) between consecutive addresses. Only addresses within the CIDR range are yielded.By default (when count is not specified), iterates through all addresses in the CIDR range from the offset to the boundary (broadcast for positive step, network for negative step).","url":"./cidrv4.ts/~/cidr4Addresses.html","deprecated":false},{"id":"namespace_cidr4broadcastaddress","kind":[{"char":"v","kind":"Variable","title":"Variable"}],"name":"cidr4BroadcastAddress","file":"cidrv4.ts","doc":"Returns the broadcast address (last IP) of a CIDR block.Alias for cidr4LastAddress.","url":"./cidrv4.ts/~/cidr4BroadcastAddress.html","deprecated":false},{"id":"namespace_cidr4contains","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidr4Contains","file":"cidrv4.ts","doc":"Checks if an IPv4 address is contained within a CIDR block.","url":"./cidrv4.ts/~/cidr4Contains.html","deprecated":false},{"id":"namespace_cidr4firstaddress","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidr4FirstAddress","file":"cidrv4.ts","doc":"Returns the first address of a CIDR block (network address).","url":"./cidrv4.ts/~/cidr4FirstAddress.html","deprecated":false},{"id":"namespace_cidr4lastaddress","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidr4LastAddress","file":"cidrv4.ts","doc":"Returns the last address of a CIDR block (broadcast address for IPv4).","url":"./cidrv4.ts/~/cidr4LastAddress.html","deprecated":false},{"id":"namespace_cidr4networkaddress","kind":[{"char":"v","kind":"Variable","title":"Variable"}],"name":"cidr4NetworkAddress","file":"cidrv4.ts","doc":"Returns the network address (first IP) of a CIDR block.Alias for cidr4FirstAddress.","url":"./cidrv4.ts/~/cidr4NetworkAddress.html","deprecated":false},{"id":"namespace_cidr4size","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidr4Size","file":"cidrv4.ts","doc":"Returns the total number of IP addresses in a CIDR block or for a given prefix length.For a /24 network, this returns 256. For a /32, this returns 1.","url":"./cidrv4.ts/~/cidr4Size.html","deprecated":false},{"id":"namespace_mask4fromprefixlength","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"mask4FromPrefixLength","file":"cidrv4.ts","doc":"Creates a network mask from an IPv4 prefix length.The prefix length must be between 0 and 32 (inclusive).","url":"./cidrv4.ts/~/mask4FromPrefixLength.html","deprecated":false},{"id":"namespace_parsecidr4","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"parseCidr4","file":"cidrv4.ts","doc":"Parses an IPv4 CIDR notation string to a Cidr4 object.Returns only the parsed values (address and prefix length).","url":"./cidrv4.ts/~/parseCidr4.html","deprecated":false},{"id":"namespace_stringifycidr4","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"stringifyCidr4","file":"cidrv4.ts","doc":"Stringifies a Cidr4 object to CIDR notation.","url":"./cidrv4.ts/~/stringifyCidr4.html","deprecated":false},{"id":"namespace_cidr6","kind":[{"char":"T","kind":"TypeAlias","title":"Type Alias"}],"name":"Cidr6","file":"cidrv6.ts","doc":"Represents an IPv6 CIDR block.Contains only the parsed values from the CIDR notation.","url":"./cidrv6.ts/~/Cidr6.html","deprecated":false},{"id":"namespace_cidr6","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"Cidr6.address","file":"cidrv6.ts","doc":"The IPv6 address from the CIDR notation","url":"./cidrv6.ts/~/Cidr6.address.html","deprecated":false},{"id":"namespace_cidr6","kind":[{"char":"p","kind":"Property","title":"Property"}],"name":"Cidr6.prefixLength","file":"cidrv6.ts","doc":"The prefix length (0-128)","url":"./cidrv6.ts/~/Cidr6.prefixLength.html","deprecated":false},{"id":"namespace_cidr6addresses","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidr6Addresses","file":"cidrv6.ts","doc":"Generates a range of IP addresses from a CIDR block.Yields IP addresses starting at the specified offset from the network address. The offset is relative to the network address (offset 0 = network address). The step parameter controls the increment (positive or negative) between consecutive addresses. Only addresses within the CIDR range are yielded.By default (when count is not specified), iterates through all addresses in the CIDR range from the offset to the boundary (last address for positive step, network for negative step).Warning: IPv6 subnets can be enormous. A /64 has 2^64 addresses. Use count or iterate lazily to avoid memory issues.","url":"./cidrv6.ts/~/cidr6Addresses.html","deprecated":false},{"id":"namespace_cidr6contains","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidr6Contains","file":"cidrv6.ts","doc":"Checks if an IPv6 address (as bigint) is contained within a CIDR block.","url":"./cidrv6.ts/~/cidr6Contains.html","deprecated":false},{"id":"namespace_cidr6firstaddress","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidr6FirstAddress","file":"cidrv6.ts","doc":"Returns the first address of a CIDR block.","url":"./cidrv6.ts/~/cidr6FirstAddress.html","deprecated":false},{"id":"namespace_cidr6lastaddress","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidr6LastAddress","file":"cidrv6.ts","doc":"Returns the last address of a CIDR block.","url":"./cidrv6.ts/~/cidr6LastAddress.html","deprecated":false},{"id":"namespace_cidr6size","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"cidr6Size","file":"cidrv6.ts","doc":"Returns the total number of IP addresses in a CIDR block or for a given prefix length.For a /120 network, this returns 256n. For a /128, this returns 1n.Warning: IPv6 subnets can be enormous. A /64 has 2^64 addresses. The result is a bigint to handle these large values.","url":"./cidrv6.ts/~/cidr6Size.html","deprecated":false},{"id":"namespace_mask6fromprefixlength","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"mask6FromPrefixLength","file":"cidrv6.ts","doc":"Creates a network mask from an IPv6 prefix length.The prefix length must be between 0 and 128 (inclusive).","url":"./cidrv6.ts/~/mask6FromPrefixLength.html","deprecated":false},{"id":"namespace_parsecidr6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"parseCidr6","file":"cidrv6.ts","doc":"Parses an IPv6 CIDR notation string to a Cidr6 object.Returns only the parsed values (address and prefix length).","url":"./cidrv6.ts/~/parseCidr6.html","deprecated":false},{"id":"namespace_stringifycidr6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"stringifyCidr6","file":"cidrv6.ts","doc":"Stringifies a Cidr6 object to CIDR notation.","url":"./cidrv6.ts/~/stringifyCidr6.html","deprecated":false},{"id":"namespace_parseipv4","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"parseIpv4","file":"ipv4.ts","doc":"Parses an IPv4 address in dotted decimal notation to a number.The function validates the format and range of each octet. Leading zeros are not allowed (except for \"0\" itself).","url":"./ipv4.ts/~/parseIpv4.html","deprecated":false},{"id":"namespace_stringifyipv4","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"stringifyIpv4","file":"ipv4.ts","doc":"Stringifies a number to an IPv4 address in dotted decimal notation.The number must represent a valid 32-bit unsigned integer (0 to 4294967295).","url":"./ipv4.ts/~/stringifyIpv4.html","deprecated":false},{"id":"namespace_compressipv6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"compressIpv6","file":"ipv6.ts","doc":"Compresses an IPv6 address to its shortest canonical form.This is equivalent to parsing and re-stringifying the address, which produces the canonical compressed representation.","url":"./ipv6.ts/~/compressIpv6.html","deprecated":false},{"id":"namespace_expandipv6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"expandIpv6","file":"ipv6.ts","doc":"Expands an IPv6 address to its full uncompressed form.Returns the address with all 8 groups fully specified with 4 hex digits each.","url":"./ipv6.ts/~/expandIpv6.html","deprecated":false},{"id":"namespace_parseipv6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"parseIpv6","file":"ipv6.ts","doc":"Parses an IPv6 address in colon-hexadecimal notation to a bigint.Supports standard IPv6 formats:Full form: 2001:0db8:0000:0000:0000:0000:0000:0001Compressed form with ::: 2001:db8::1Mixed IPv4 form: ::ffff:192.168.1.1Zone IDs are stripped: fe80::1%eth0 becomes fe80::1","url":"./ipv6.ts/~/parseIpv6.html","deprecated":false},{"id":"namespace_stringifyipv6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"stringifyIpv6","file":"ipv6.ts","doc":"Stringifies a bigint to an IPv6 address in compressed colon-hexadecimal notation.The output uses the canonical compressed form:Leading zeros in each group are omittedThe longest run of consecutive all-zero groups is replaced with ::If there are multiple runs of the same length, the first one is compressed","url":"./ipv6.ts/~/stringifyIpv6.html","deprecated":false},{"id":"namespace_isvalid","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isValid","file":"validate.ts","doc":"Checks if a string is any valid IP address or CIDR notation.Accepts IPv4, IPv6, IPv4 CIDR, and IPv6 CIDR formats.","url":"./validate.ts/~/isValid.html","deprecated":false},{"id":"namespace_validate","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"validate","file":"validate.ts","doc":"Validates and identifies any IP address or CIDR notation string.Attempts to parse the string as IPv4, IPv6, IPv4 CIDR, or IPv6 CIDR and returns a discriminated union indicating what was found. Strings containing / are tested as CIDR first; others are tested as plain addresses.","url":"./validate.ts/~/validate.html","deprecated":false},{"id":"namespace_validationresult","kind":[{"char":"T","kind":"TypeAlias","title":"Type Alias"}],"name":"ValidationResult","file":"validate.ts","doc":"The result of the validate function.Discriminated union on kind:\"ipv4\" — valid IPv4 address with parsed value as a 32-bit number\"ipv6\" — valid IPv6 address with parsed value as a 128-bit bigint\"cidr4\" — valid IPv4 CIDR with parsed value as a Cidr4\"cidr6\" — valid IPv6 CIDR with parsed value as a Cidr6\"invalid\" — the string is not a valid IP address or CIDR notation","url":"./validate.ts/~/ValidationResult.html","deprecated":false},{"id":"namespace_isvalidcidr4","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isValidCidr4","file":"validatev4.ts","doc":"Checks if a string is valid IPv4 CIDR notation.","url":"./validatev4.ts/~/isValidCidr4.html","deprecated":false},{"id":"namespace_isvalidipv4","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isValidIpv4","file":"validatev4.ts","doc":"Checks if a string is a valid IPv4 address in dotted decimal notation.","url":"./validatev4.ts/~/isValidIpv4.html","deprecated":false},{"id":"namespace_isvalidcidr6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isValidCidr6","file":"validatev6.ts","doc":"Checks if a string is valid IPv6 CIDR notation.","url":"./validatev6.ts/~/isValidCidr6.html","deprecated":false},{"id":"namespace_isvalidipv6","kind":[{"char":"f","kind":"Function","title":"Function"}],"name":"isValidIpv6","file":"validatev6.ts","doc":"Checks if a string is a valid IPv6 address in colon-hexadecimal notation.Accepts full form, compressed form with ::, IPv4-mapped addresses (::ffff:192.168.1.1), and addresses with zone IDs (fe80::1%eth0).","url":"./validatev6.ts/~/isValidIpv6.html","deprecated":false}]};
})()